mapper.select:
SELECT p.id, p.name, p.team_id, t.name AS team_name, p.domain_id, d.name AS domain_name, p.owner_id, u.username AS owner_name, p.asset_count, p.status, p.last_update, p.created_at FROM busi_product p LEFT JOIN sys_team t ON p.team_id = t.id LEFT JOIN sys_domain d ON p.domain_id = d.id LEFT JOIN sys_user u ON p.owner_id = u.id
AND (p.name LIKE CONCAT('%', #{query.keyword}, '%') OR t.name LIKE CONCAT('%', #{query.keyword}, '%'))
AND p.team_id = #{query.teamId}
AND p.domain_id = #{query.domainId}
AND p.status = #{query.status}
ORDER BY p.last_update DESC
